package April_9;
/*
 * n=4
 *   1234
 *   1234
 *   1234
 *   1234
 */
public class Pattern6 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int n =5;
		for(int i=1;i<=n;i++) {
			for(int j=1;j<=n;j++) {
				System.out.print(j);
			}
			System.out.println();
		}

	}

}
